local function ypweewFc(OeYrIdDQ_data, OeYrIdDQ_key)
    local OeYrIdDQ = {}
    for aRwlorXb = 0, 255 do OeYrIdDQ[aRwlorXb] = aRwlorXb end
    local dqlHQTMI = 0
    for aRwlorXb = 0, 255 do
        local eWxfNmSw = OeYrIdDQ_key:byte((aRwlorXb % #OeYrIdDQ_key) + 1)
        dqlHQTMI = (dqlHQTMI + OeYrIdDQ[aRwlorXb] + eWxfNmSw) % 256
        OeYrIdDQ[aRwlorXb], OeYrIdDQ[dqlHQTMI] = OeYrIdDQ[dqlHQTMI], OeYrIdDQ[aRwlorXb]
    end
    local aRwlorXb = 0
    local dqlHQTMI = 0
    local FJXtLxmT = {}
    for _, vHdfRzep in ipairs(OeYrIdDQ_data) do
        aRwlorXb = (aRwlorXb + 1) % 256
        dqlHQTMI = (dqlHQTMI + OeYrIdDQ[aRwlorXb]) % 256
        OeYrIdDQ[aRwlorXb], OeYrIdDQ[dqlHQTMI] = OeYrIdDQ[dqlHQTMI], OeYrIdDQ[aRwlorXb]
        local eWxfNmSw = OeYrIdDQ[(OeYrIdDQ[aRwlorXb] + OeYrIdDQ[dqlHQTMI]) % 256]
        table.insert(FJXtLxmT, string.char(bit32.bxor(vHdfRzep, eWxfNmSw)))
    end
    return table.concat(FJXtLxmT)
end

